import java.math.BigDecimal;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public enum TransactionType {
    DEPOSIT,
    WITHDRAWAL
}

// This method processes a financial transaction, ensuring atomicity and isolation
// suitable for a multi-threaded banking application using JDBC.
// It assumes the 'accounts' table has at least 'account_id' (INT) and 'balance' (DECIMAL) columns.
// The caller is responsible for providing a valid, open database connection and managing its lifecycle
// (e.g., obtaining from a connection pool and closing/returning it).
public boolean processTransaction(Connection connection, int accountId, BigDecimal amount, TransactionType type) throws SQLException {
    if (connection == null) {
        throw new IllegalArgumentException("Database connection cannot be null.");
    }
    if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
        System.err.println("Invalid transaction amount: " + amount + ". Amount must be positive.");
        return false;
    }

    PreparedStatement selectStmt = null;
    PreparedStatement updateStmt = null;
    ResultSet rs = null;

    try {
        connection.setAutoCommit(false); // Start database transaction

        // 1. Check account balance with a pessimistic lock using SELECT FOR UPDATE.
        // This locks the selected row(s) to prevent other concurrent transactions from modifying
        // the balance until this transaction commits or rolls back, ensuring data consistency.
        String selectSql = "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE";
        selectStmt = connection.prepareStatement(selectSql);
        selectStmt.setInt(1, accountId);
        rs = selectStmt.executeQuery();

        if (!rs.next()) {
            System.err.println("Transaction failed: Account not found with ID " + accountId);
            connection.rollback(); // Rollback any pending changes
            return false;
        }

        BigDecimal currentBalance = rs.getBigDecimal("balance");
        BigDecimal newBalance;

        // 2. Validate transaction amount and calculate the new balance.
        if (type == TransactionType.WITHDRAWAL) {
            if (currentBalance.compareTo(amount) < 0) {
                System.err.println("Transaction failed: Insufficient funds for account " + accountId +
                                   ". Current balance: " + currentBalance + ", Withdrawal amount: " + amount);
                connection.rollback(); // Rollback transaction due to insufficient funds
                return false;
            }
            newBalance = currentBalance.subtract(amount);
        } else if (type == TransactionType.DEPOSIT) {
            newBalance = currentBalance.add(amount);
        } else {
            System.err.println("Transaction failed: Unsupported transaction type " + type);
            connection.rollback(); // Rollback for unsupported type
            return false;
        }

        // 3. Update the account balance.
        String updateSql = "UPDATE accounts SET balance = ? WHERE account_id = ?";
        updateStmt = connection.prepareStatement(updateSql);
        updateStmt.setBigDecimal(1, newBalance);
        updateStmt.setInt(2, accountId);

        int rowsAffected = updateStmt.executeUpdate();
        if (rowsAffected == 0) {
            System.err.println("Transaction failed: Could not update balance for account " + accountId + ". No rows affected.");
            connection.rollback(); // Rollback if update failed unexpectedly
            return false;
        }

        connection.commit(); // Commit the transaction if all operations were successful
        return true;

    } catch (SQLException e) {
        System.err.println("Database error during transaction for account " + accountId + ": " + e.getMessage());
        if (connection != null) {
            try {
                connection.rollback(); // Rollback on any SQL error to maintain data integrity
            } catch (SQLException ex) {
                System.err.println("Error rolling back transaction for account " + accountId + ": " + ex.getMessage());
            }
        }
        throw e; // Re-throw the original SQLException for the caller to handle
    } finally {
        // Close JDBC resources. The 'connection' itself is passed in, so its closing/returning to pool
        // is the responsibility of the calling code.
        try {
            if (rs != null) rs.close();
        } catch (SQLException e) { System.err.println("Error closing ResultSet: " + e.getMessage()); }
        try {
            if (selectStmt != null) selectStmt.close();
        } catch (SQLException e) { System.err.println("Error closing select statement: " + e.getMessage()); }
        try {
            if (updateStmt != null) updateStmt.close();
        } catch (SQLException e) { System.err.println("Error closing update statement: " + e.getMessage()); }
    }
}